def decrypt_caesar(text, shift=13):
    result = ""
    for ch in text:
        if ch.isalpha():
            base = ord("a") if ch.islower() else ord("A")
            result += chr((ord(ch)-base+shift) % 26 + base)
        else:
            result += ch
    return result

